class ScienceSimulation {
    constructor(container, initialInputs) {
        this.container = container;
        this.canvas = document.createElement('canvas');
        this.ctx = this.canvas.getContext('2d');
        this.container.appendChild(this.canvas);

        this.inputs = initialInputs;
        this.stepIndex = 0;
        this.waves = [];
        this.time = 0;
        this.lastEmitTime = 0;
        this.lastFrameTime = performance.now();

        this.sourceX = 0;
        this.obsX = 0;

        this.resize();
        window.addEventListener('resize', () => this.resize());

        this.animate = this.animate.bind(this);
        this.animationId = requestAnimationFrame(this.animate);
    }

    resize() {
        this.canvas.width = this.container.clientWidth;
        this.canvas.height = this.container.clientHeight;
        this.sourceX = this.canvas.width * 0.2;
        this.obsX = this.canvas.width * 0.8;
    }

    animate(now) {
        const dt = (now - this.lastFrameTime) / 1000;
        this.lastFrameTime = now;

        if (dt < 0.1) { // Prevent huge jumps
            this.time += dt;
            this.update(dt);
        }

        this.draw();
        this.animationId = requestAnimationFrame(this.animate);
    }

    update(dt) {
        const vs = (this.stepIndex === 0 || this.stepIndex === 2) ? 0 : parseFloat(this.inputs.sourceVel);
        const vo = (this.stepIndex === 0 || this.stepIndex === 1) ? 0 : parseFloat(this.inputs.obsVel);
        const vSound = parseFloat(this.inputs.soundSpeed);
        const freq = parseFloat(this.inputs.sourceFreq);

        // Update positions (scaled for visual clarity)
        // 1 unit = 1 pixel for simplicity in this coordinate space
        this.sourceX += vs * dt;
        this.obsX += vo * dt;

        // Wrap around logic
        const margin = 100;
        if (this.sourceX > this.canvas.width + margin) this.sourceX = -margin;
        if (this.sourceX < -margin) this.sourceX = this.canvas.width + margin;
        if (this.obsX > this.canvas.width + margin) this.obsX = -margin;
        if (this.obsX < -margin) this.obsX = this.canvas.width + margin;

        // Emit waves
        const period = 1 / freq;
        if (this.time - this.lastEmitTime > period) {
            this.waves.push({
                x: this.sourceX,
                y: this.canvas.height / 2,
                t0: this.time
            });
            this.lastEmitTime = this.time;
        }

        // Filter old waves
        this.waves = this.waves.filter(w => (this.time - w.t0) * vSound < this.canvas.width * 1.5);
    }

    draw() {
        const { ctx, canvas, waves, time, inputs, stepIndex } = this;
        const vSound = parseFloat(inputs.soundSpeed);

        // Background
        ctx.fillStyle = '#0f172a';
        ctx.fillRect(0, 0, canvas.width, canvas.height);

        // Draw Ground
        ctx.strokeStyle = '#334155';
        ctx.beginPath();
        ctx.moveTo(0, canvas.height / 2 + 40);
        ctx.lineTo(canvas.width, canvas.height / 2 + 40);
        ctx.stroke();

        // Draw Waves
        ctx.lineWidth = 2;
        waves.forEach(w => {
            const radius = (time - w.t0) * vSound;
            const age = time - w.t0;
            const alpha = Math.max(0, 1 - radius / (canvas.width * 1.2));

            ctx.strokeStyle = `rgba(59, 130, 246, ${alpha})`;
            ctx.beginPath();
            ctx.arc(w.x, w.y, radius, 0, Math.PI * 2);
            ctx.stroke();
        });

        // Draw Source (Speaker)
        ctx.fillStyle = '#ef4444';
        ctx.beginPath();
        ctx.arc(this.sourceX, canvas.height / 2, 15, 0, Math.PI * 2);
        ctx.fill();
        ctx.fillStyle = '#ffffff';
        ctx.font = 'bold 12px sans-serif';
        ctx.textAlign = 'center';
        ctx.fillText('SOURCE', this.sourceX, canvas.height / 2 - 25);

        // Draw Observer
        ctx.fillStyle = '#10b981';
        ctx.beginPath();
        ctx.arc(this.obsX, canvas.height / 2, 15, 0, Math.PI * 2);
        ctx.fill();
        ctx.fillStyle = '#ffffff';
        ctx.fillText('OBSERVER', this.obsX, canvas.height / 2 - 25);

        // Velocity Vectors
        const vs = (stepIndex === 0 || stepIndex === 2) ? 0 : parseFloat(inputs.sourceVel);
        const vo = (stepIndex === 0 || stepIndex === 1) ? 0 : parseFloat(inputs.obsVel);

        this.drawVector(this.sourceX, canvas.height / 2 + 20, vs, '#f87171', 'v_s');
        this.drawVector(this.obsX, canvas.height / 2 + 20, vo, '#34d399', 'v_o');
    }

    drawVector(x, y, mag, color, label) {
        if (Math.abs(mag) < 1) return;
        const length = mag * 0.5;
        this.ctx.strokeStyle = color;
        this.ctx.fillStyle = color;
        this.ctx.lineWidth = 3;
        this.ctx.beginPath();
        this.ctx.moveTo(x, y);
        this.ctx.lineTo(x + length, y);
        this.ctx.stroke();

        // Arrowhead
        const head = mag > 0 ? 5 : -5;
        this.ctx.beginPath();
        this.ctx.moveTo(x + length, y);
        this.ctx.lineTo(x + length - head, y - 5);
        this.ctx.lineTo(x + length - head, y + 5);
        this.ctx.fill();

        this.ctx.font = '10px sans-serif';
        this.ctx.fillText(`${label}: ${mag}m/s`, x + length / 2, y + 15);
    }

    getSteps(inputs) {
        const v = parseFloat(inputs.soundSpeed);
        const fs = parseFloat(inputs.sourceFreq);
        const vs = parseFloat(inputs.sourceVel);
        const vo = parseFloat(inputs.obsVel);

        const fObsSourceOnly = (fs * (v / (v - vs))).toFixed(2);
        const fObsObsOnly = (fs * ((v - vo) / v)).toFixed(2);
        const fObsTotal = (fs * ((v - vo) / (v - vs))).toFixed(2);

        return [
            {
                title: "Stationary Case",
                description: "When both the source and observer are stationary ($v_s = 0, v_o = 0$), the observer hears the same frequency emitted by the source: **" + fs + " Hz**. The wavefronts are perfectly concentric circles."
            },
            {
                title: "Moving Source",
                description: "The source moves at **" + vs + " m/s**. Waves in front of the source are compressed (higher frequency), while waves behind are stretched (lower frequency). Observed frequency: $f' = f \\frac{v}{v - v_s} = " + fObsSourceOnly + "$ Hz."
            },
            {
                title: "Moving Observer",
                description: "The observer moves at **" + vo + " m/s**. By moving towards or away from the wavefronts, the observer encounters them more or less frequently. Observed frequency: $f' = f \\frac{v - v_o}{v} = " + fObsObsOnly + "$ Hz."
            },
            {
                title: "Combined Doppler Effect",
                description: "With both moving, the final observed frequency is $f' = f \\frac{v - v_o}{v - v_s} = " + fObsTotal + "$ Hz. If the source exceeds the speed of sound ($v_s > v$), a shock wave (sonic boom) forms as wavefronts overlap!"
            }
        ];
    }

    render(inputs, stepIndex) {
        if (this.stepIndex !== stepIndex) {
            this.sourceX = this.canvas.width * 0.2;
            this.obsX = this.canvas.width * 0.8;
            this.waves = [];
            this.time = 0;
            this.lastEmitTime = 0;
        }
        this.inputs = inputs;
        this.stepIndex = stepIndex;
    }
}
